parameters.query:
SELECT EXISTS (
  SELECT 1 FROM public.llamadas_agendadas
  WHERE lead_id = {{ $json.lead_id }}
    AND estado IN ('agendada','realizada')
) AS debe_cerrar;

UPDATE public.seguimientos_syh
SET estado         = 'cerrado',
    cerrado_en     = now(),
    cerrado_motivo = 'llamada_agendada'
WHERE lead_id = {{ $('Loop 1 a 1').item.json.lead_id }}
  AND estado  = 'pendiente';

